//2.7.101 | 2022-01-01 | raj | DFCT0010695 - Form Customization - Search Results page does not recognizing the Form Preferences when it loads the form 
//                             This was using the filter and not a scripted source before.
// Script Continued Below

(function(query) {
	var results = [];
	/* Calculate your results here. */
	var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
	// DFCT0010695
	var userPreferences = oUserPref.loadMyFormPreferences();

	var taskerGR = new GlideRecord("x_153465_discovert_route_task_instance");
	taskerGR.addQuery('123TEXTQUERY321', query);
	taskerGR.setLimit(data.limit);
	taskerGR.query();
	while (taskerGR.next()) {
		if (!$sp.canReadRecord(taskerGR))
			continue;

		// TODO, use default page here
		var defaultView = 'sp';
		var sys_id = taskerGR.getUniqueValue();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(sys_id, defaultView);
		var task = {};
		task.text = taskerGR.short_description;
		task.url = url_Properties.portal_url_ref + '?id=' + url_Properties.pageId + 
			'&table=x_153465_discovert_route_task_instance' + 
			'&sys_id=' + sys_id  + 
			'&view=' + url_Properties.view;

		task.target = '_blank';
		task.primary = taskerGR.getDisplayValue('task_name');
		task.fields = [];
		// Task Name, Parent Task, Classification, State, Status, Risk Flag, Primary Assignee, Primary Office, Active, Assigned Member
		var fieldList = ["task_name", "short_description", "parent", "classification", "state", "status", "risk_flag", "primary_assignee",
						"primary_office", "active", "assigned_to"];
		for (i = 0; i < fieldList.length; i++) {
			var field = {};
			field.label = taskerGR[fieldList[i]].getLabel();
			field.display_value = taskerGR.getDisplayValue(fieldList[i]);
			task.fields.push(field);				
		}
		results.push(task);	
	}

  return results;
})(query);

